const files = $json.files || [];
const taskDesc = $json.task?.description || $json.description || '';
const projectGoal = $json.project_goal || '';
const code = files.map(f => `### ${f.path}\n\`\`\`\n${f.content}\n\`\`\``).join('\n\n');
const context = (projectGoal || taskDesc) ? `\n\nProject Goal: ${projectGoal}\nCurrent Task: ${taskDesc}\n` : '';
return [{
  json: {
    model: 'qwen/qwen3.5-9b',
    messages: [{
      role: 'user',
      content: `You are a Security Engineer. Review this code for OWASP Top 10 issues.${context}\n\nCode:\n${code}\n\nReturn ONLY valid JSON (no markdown, no explanation):\n{"security_score":number,"critical_issues":[{"issue":"...","severity":"high/medium/low","fix":"..."}],"high_priority":[{"issue":"...","severity":"...","fix":"..."}],"recommendations":["..."]}`
    }],
    temperature: 0.3,
    top_p: 0.8,
    top_k: 20,
    min_p: 0.0,
    presence_penalty: 0.0,
    max_tokens: 2048
  }
}];

const raw = $json.choices[0].message.content || '';
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) content = content.split('</think>').pop().trim();
// Strip markdown code block wrappers
content = content.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
// Try to extract JSON object if surrounded by prose
const jsonMatch = content.match(/\{[\s\S]*\}/);
let review;
try { review = JSON.parse(jsonMatch ? jsonMatch[0] : content); } catch (e) { review = { raw_output: content }; }
const trigger = $('Execute Workflow Trigger').first().json;
return [{ json: { security_review: review, files: trigger.files, task: trigger.task, project_goal: trigger.project_goal } }];
